item.content:encoded:
/* Container */
.custom-contact-form {
  background: radial-gradient(circle at top left, #111 0%, #0b0b0b 60%);
  padding: clamp(24px, 4vw, 48px);
  border-radius: 24px;
  max-width: 820px;
  margin: auto;
  color: #fff;
  font-family: 'DM Sans', sans-serif;
  box-shadow: 0 20px 80px rgba(0,0,0,0.6);
}

/* Header */
.custom-contact-form h2 {
  font-family: 'Syne', sans-serif !important;
  font-weight: 700;
  font-size: clamp(24px, 3vw, 34px);
  line-height: 1.2;
  letter-spacing: -0.5px;
  margin-bottom: 6px;
}

.custom-contact-form .subtitle {
  font-size: clamp(13px, 1.2vw, 15px);
  color: #9a9a9a;
  margin-bottom: 28px;
}

/* Layout */
.custom-contact-form .row {
  display: flex;
  gap: 20px;
}
@media (max-width: 640px) {
  .custom-contact-form .row {
    flex-direction: column;
  }
}

/* Fields */
.custom-contact-form .field {
  margin-bottom: 20px;
  flex: 1;
}

.custom-contact-form label {
  font-size: 11px;
  color: #8a8a8a;
  margin-bottom: 6px;
  display: block;
  letter-spacing: 1px;
  font-weight: 500;
}

/* Inputs */
.custom-contact-form input,
.custom-contact-form textarea,
.custom-contact-form select {
  width: 100%;
  padding: 14px 16px;
  border-radius: 12px;
  border: 1px solid #1f1f1f;
  background: linear-gradient(145deg, #111, #1a1a1a);
  color: #fff;
  font-size: 14px;
  font-family: 'DM Sans', sans-serif;
  transition: all 0.25s ease;
}

/* Glow effect on focus */
.custom-contact-form input:focus,
.custom-contact-form textarea:focus,
.custom-contact-form select:focus {
  border-color: #c6ff00;
  box-shadow:
    0 0 0 1px rgba(198,255,0,0.3),
    0 0 12px rgba(198,255,0,0.15);
  background: linear-gradient(145deg, #151515, #1d1d1d);
}

/* Placeholder styling */
.custom-contact-form ::placeholder {
  color: #666;
}

/* Select highlight */
.custom-contact-form select {
  border: 1px solid rgba(198,255,0,0.4);
}

/* 🔥 FIX: Dropdown options (this was the problem) */
.custom-contact-form select option {
  background-color: #1a1a1a !important;
  color: #ffffff !important;
}

.custom-contact-form select option:hover,
.custom-contact-form select option:checked {
  background-color: #2a2a2e !important;
  color: #ffffff !important;
}

/* Textarea */
.custom-contact-form textarea {
  min-height: 130px;
  resize: none;
}

/* Button */
.custom-contact-form input[type="submit"] {
  width: 100%;
  padding: 16px;
  border-radius: 999px;
  border: none;
  background: linear-gradient(90deg, #c6ff00, #d9ff4d);
  color: #000;
  font-weight: 600;
  font-size: 15px;
  cursor: pointer;
  transition: all 0.3s ease;
  margin-top: 10px;
}

/* Button hover (soft glow bloom) */
.custom-contact-form input[type="submit"]:hover {
  box-shadow:
    0 0 20px rgba(198,255,0,0.4),
    0 0 40px rgba(198,255,0,0.2);
  transform: translateY(-1px);
}

/* Button click */
.custom-contact-form input[type="submit"]:active {
  transform: translateY(1px);
  box-shadow: 0 0 10px rgba(198,255,0,0.3);
}
